/* Reading List Dashboard — vanilla JS, read-only
 * Data source: /assets/data/reading_list.json (generated by scripts/sync_reading_list.py)
 */

(function () {
  "use strict";

  const DATA_URL = "/assets/data/reading_list.json";
  const LS_PREFIX = "rl_";

  // ── State ──────────────────────────────────────────────────────────────────
  let allItems = [];
  let allThemes = [];
  let meta = {};

  let state = {
    view:    lsGet("view",    "card"),
    theme:   lsGet("theme",  "all"),
    status:  lsGet("status", "all"),
    stars:   lsGet("stars",  "0"),
    year:    lsGet("year",   "all"),
    sort:    lsGet("sort",   "year-desc"),
    query:   "",
  };

  function lsGet(k, def) {
    try { return localStorage.getItem(LS_PREFIX + k) || def; } catch { return def; }
  }
  function lsSet(k, v) {
    try { localStorage.setItem(LS_PREFIX + k, v); } catch {}
  }
  function setState(key, val) {
    state[key] = val;
    lsSet(key, val);
    render();
  }

  // ── Helpers ────────────────────────────────────────────────────────────────
  function stars(n) { return "★".repeat(n) + "☆".repeat(Math.max(0, 5 - n)); }

  const STATUS_LABEL = { "to-read": "To read", reading: "Reading", done: "Done", "in-progress": "In progress", skipped: "Skipped" };
  const STATUS_COLOR = { "to-read": "#888", reading: "#FFD700", done: "#4CAF50", "in-progress": "#FFD700", skipped: "#9E9E9E" };

  const TYPE_STYLE = {
    "Review":      { bg: "#e8f5e9", color: "#2e7d32", border: "#2e7d32" },
    "Article":     { bg: "#f5f5f5", color: "#555",    border: "#999"    },
    "Preprint":    { bg: "#f5f5f5", color: "#888",    border: "#bbb"    },
    "Perspective": { bg: "#fff3e0", color: "#e65100", border: "#e65100" },
    "Position":    { bg: "#f3e5f5", color: "#6a1b9a", border: "#6a1b9a" },
  };

  function typeStyle(t) {
    return TYPE_STYLE[t] || { bg: "#f5f5f5", color: "#777", border: "#bbb" };
  }

  function typeBadgeHtml(articleType) {
    if (!articleType) return "";
    const s = typeStyle(articleType);
    return `<span class="rl-type-badge" style="background:${s.bg};color:${s.color};border-color:${s.border}">${articleType}</span>`;
  }

  function applyFilters(items) {
    return items.filter(it => {
      if (state.theme !== "all" && it.theme !== state.theme) return false;
      if (state.status !== "all" && it.status !== state.status) return false;
      if (state.stars !== "0" && it.stars < parseInt(state.stars)) return false;
      if (state.year !== "all" && String(it.year) !== state.year) return false;
      if (state.query) {
        const q = state.query.toLowerCase();
        if (!(it.title || "").toLowerCase().includes(q) &&
            !(it.first_author || "").toLowerCase().includes(q) &&
            !(it.tags || []).join(" ").toLowerCase().includes(q) &&
            !(it.memo || "").toLowerCase().includes(q)) return false;
      }
      return true;
    });
  }

  function applySortKey(arr) {
    const m = state.sort.match(/^(.+)-(asc|desc)$/);
    const [key, dir] = m ? [m[1], m[2]] : ["priority", "desc"];
    const sign = dir === "asc" ? 1 : -1;
    return [...arr].sort((a, b) => {
      if (key === "year")         return sign * ((a.year || 0) - (b.year || 0)) || (b.priority || 0) - (a.priority || 0);
      if (key === "author")       return sign * (a.first_author || "").localeCompare(b.first_author || "") || (b.priority || 0) - (a.priority || 0);
      if (key === "title")        return sign * (a.title || "").localeCompare(b.title || "");
      if (key === "status")       return sign * (a.status || "").localeCompare(b.status || "") || (b.priority || 0) - (a.priority || 0);
      if (key === "article_type") return sign * (a.article_type || "").localeCompare(b.article_type || "") || (b.priority || 0) - (a.priority || 0);
      return sign * ((a.priority || 0) - (b.priority || 0)) || (a.title || "").localeCompare(b.title || "");
    });
  }

  // ── Render ─────────────────────────────────────────────────────────────────
  function render() {
    renderStats();
    renderToolbar();
    const filtered = applySortKey(applyFilters(allItems));
    document.getElementById("rl-count").textContent = `${filtered.length} / ${allItems.length} items`;
    if (state.view === "table") renderTable(filtered);
    else renderCards(filtered);
  }

  function renderStats() {
    const el = document.getElementById("rl-stats");
    if (!el || !meta.total) return;
    el.innerHTML = `<span class="rl-stat">Total <strong>${meta.total}</strong></span>`;
  }

  function renderToolbar() {
    // Theme selector options
    const themeEl = document.getElementById("rl-filter-theme");
    if (themeEl && themeEl.options.length <= 1) {
      allThemes.forEach(t => {
        const o = document.createElement("option");
        o.value = t; o.textContent = t.replace(/^Theme \d+: /, "");
        themeEl.appendChild(o);
      });
    }
    if (themeEl) themeEl.value = state.theme;

    // Year selector options
    const years = [...new Set(allItems.map(i => i.year).filter(y => y > 0))].sort((a, b) => b - a);
    const yearEl = document.getElementById("rl-filter-year");
    if (yearEl && yearEl.options.length <= 1) {
      years.forEach(y => {
        const o = document.createElement("option"); o.value = y; o.textContent = y;
        yearEl.appendChild(o);
      });
    }
    if (yearEl) yearEl.value = state.year;

    const statusEl = document.getElementById("rl-filter-status");
    if (statusEl) statusEl.value = state.status;

    const starsEl = document.getElementById("rl-filter-stars");
    if (starsEl) starsEl.value = state.stars;

    const sortEl = document.getElementById("rl-sort");
    if (sortEl) sortEl.value = state.sort;

    // View buttons
    document.querySelectorAll(".rl-view-btn").forEach(btn => {
      btn.classList.toggle("active", btn.dataset.view === state.view);
    });

    // Hide sort dropdown in table mode (columns handle it)
    const sortWrap = document.getElementById("rl-sort-wrap");
    if (sortWrap) sortWrap.style.display = state.view === "table" ? "none" : "";
  }

  // ── Card View ──────────────────────────────────────────────────────────────
  function renderCards(items) {
    const container = document.getElementById("rl-container");
    container.innerHTML = "";
    container.style.display = "";

    const tableEl = document.getElementById("rl-table-wrap");
    if (tableEl) tableEl.style.display = "none";

    if (!items.length) {
      container.innerHTML = '<p style="opacity:0.5;text-align:center;padding:2em">No results</p>';
      return;
    }

    // Group by theme
    const byTheme = new Map();
    items.forEach(it => {
      const key = it.theme || "Other";
      if (!byTheme.has(key)) byTheme.set(key, []);
      byTheme.get(key).push(it);
    });

    // Within each theme: sort by year desc, then by stars desc
    byTheme.forEach(group => {
      group.sort((a, b) => (b.year || 0) - (a.year || 0) || (b.stars || 0) - (a.stars || 0));
    });

    // Section render order: follow allThemes ordering, then "Other" last
    const sectionOrder = [...allThemes.filter(t => byTheme.has(t)),
                         ...[...byTheme.keys()].filter(t => !allThemes.includes(t))];

    sectionOrder.forEach(theme => {
      const group = byTheme.get(theme);
      if (!group || !group.length) return;

      const section = document.createElement("div");
      section.className = "rl-section";

      const h = document.createElement("h3");
      h.className = "rl-theme-heading";
      h.textContent = theme || "Other";
      section.appendChild(h);

      // Sub-group by article_type: Reviews first, then others
      const reviews = group.filter(it => it.article_type === "Review");
      const others  = group.filter(it => it.article_type !== "Review");

      function renderGroup(groupItems, label) {
        if (!groupItems.length) return;
        if (label && reviews.length && others.length) {
          const lbl = document.createElement("div");
          lbl.className = "rl-type-section-label";
          lbl.textContent = label;
          section.appendChild(lbl);
        }
        const grid = document.createElement("div");
        grid.className = "rl-grid";
        groupItems.forEach(it => {
          const card = document.createElement("div");
          card.className = "rl-card";
          if (it.done) card.classList.add("rl-card--done");

          const tagsHtml = (it.tags || []).slice(0, 4).map(t =>
            `<span class="rl-tag">${t}</span>`).join("");

          const subthemeHtml = it.subtheme
            ? `<div class="rl-card__subtheme">${it.subtheme.replace(/^\d+[a-z]\.\s*/i, "")}</div>`
            : "";

          const tldrHtml = it.tldr
            ? `<div class="rl-card__tldr">${it.tldr}</div>`
            : "";

          card.innerHTML = `
            <div class="rl-card__top">
              <span class="rl-stars" title="${it.stars}★">${stars(it.stars)}</span>
              ${typeBadgeHtml(it.article_type)}
            </div>
            ${subthemeHtml}
            <div class="rl-card__title">${it.url
              ? `<a href="${it.url}" target="_blank" rel="noopener">${it.title}</a>`
              : it.title}</div>
            <div class="rl-card__venue">${[it.year || null, it.first_author, it.venue].filter(Boolean).join(" · ")}</div>
            ${tldrHtml}
            ${tagsHtml ? `<div class="rl-card__tags">${tagsHtml}</div>` : ""}
            ${it.memo ? `<div class="rl-card__memo">${it.memo}</div>` : ""}`;

          grid.appendChild(card);
        });
        section.appendChild(grid);
      }

      renderGroup(reviews, "Reviews");
      renderGroup(others,  "Research Papers");

      container.appendChild(section);
    });
  }

  // ── Reset filters/sort ─────────────────────────────────────────────────────
  function resetState() {
    state = { view: "card", theme: "all", status: "all", stars: "0", year: "all", sort: "year-desc", query: "" };
    Object.entries(state).forEach(([k, v]) => { if (k !== "query") lsSet(k, v); });
    const searchEl = document.getElementById("rl-search");
    if (searchEl) searchEl.value = "";
    tableSort = { key: "year", dir: "desc" };
    render();
  }

  // ── Table View ─────────────────────────────────────────────────────────────
  let tableSort = { key: "year", dir: "desc" };

  const TABLE_COLS = [
    { label: "⭐",      key: "priority",     width: "50px"  },
    { label: "Title",   key: "title",         width: null    },
    { label: "Year",    key: "year",          width: "58px"  },
    { label: "Author",  key: "author",        width: "100px" },
    { label: "Type",    key: "article_type",  width: "80px"  },
    { label: "Theme",   key: null,            width: "120px" },
    { label: "Subtheme",key: null,            width: "150px" },
    { label: "Tags",    key: null,            width: "110px" },
  ];

  function renderTable(items) {
    const container = document.getElementById("rl-container");
    container.style.display = "none";

    let wrap = document.getElementById("rl-table-wrap");
    if (!wrap) {
      wrap = document.createElement("div");
      wrap.id = "rl-table-wrap";
      container.parentNode.insertBefore(wrap, container.nextSibling);
    }
    wrap.style.display = "";
    wrap.innerHTML = "";

    const table = document.createElement("table");
    table.className = "rl-table";

    // Header
    const thead = table.createTHead();
    const hrow = thead.insertRow();
    TABLE_COLS.forEach(col => {
      const th = document.createElement("th");
      th.textContent = col.label;
      if (col.width) th.style.width = col.width;
      if (col.key) {
        th.style.cursor = "pointer";
        th.title = "Click to sort";
        const isActive = tableSort.key === col.key;
        if (isActive) th.textContent += tableSort.dir === "asc" ? " ↑" : " ↓";
        else th.textContent += " ↕";
        th.addEventListener("click", () => {
          if (tableSort.key === col.key) {
            tableSort.dir = tableSort.dir === "asc" ? "desc" : "asc";
          } else {
            tableSort.key = col.key;
            tableSort.dir = (col.key === "title" || col.key === "author" || col.key === "article_type") ? "asc" : "desc";
          }
          state.sort = tableSort.key + "-" + tableSort.dir;
          lsSet("sort", state.sort);
          render();
        });
      }
      hrow.appendChild(th);
    });

    // Body
    const tbody = table.createTBody();
    if (!items.length) {
      const row = tbody.insertRow();
      const cell = row.insertCell();
      cell.colSpan = TABLE_COLS.length;
      cell.textContent = "No results";
      cell.style.textAlign = "center";
      cell.style.padding = "2em";
    } else {
      items.forEach(it => {
        const row = tbody.insertRow();
        if (it.done) row.classList.add("rl-row--done");

        // ⭐ stars
        const tdStar = row.insertCell();
        tdStar.className = "rl-td-center";
        tdStar.textContent = it.stars ? "★".repeat(it.stars) : "";

        // Title + memo
        const tdTitle = row.insertCell();
        tdTitle.innerHTML = it.url
          ? `<a href="${it.url}" target="_blank" rel="noopener">${it.title}</a>`
          : it.title;
        if (it.memo) {
          const m = document.createElement("div");
          m.className = "rl-table-memo";
          m.textContent = it.memo;
          tdTitle.appendChild(m);
        }

        // Year
        const tdYear = row.insertCell();
        tdYear.className = "rl-td-center";
        tdYear.textContent = it.year || "";

        // Author
        const tdAuthor = row.insertCell();
        tdAuthor.textContent = it.first_author || "";

        // Type badge
        const tdType = row.insertCell();
        tdType.className = "rl-td-center";
        if (it.article_type) {
          const s = typeStyle(it.article_type);
          const badge = document.createElement("span");
          badge.className = "rl-type-badge";
          badge.style.background = s.bg;
          badge.style.color = s.color;
          badge.style.borderColor = s.border;
          badge.textContent = it.article_type;
          tdType.appendChild(badge);
        }

        // Theme (short — strip "Theme N: " prefix)
        const tdTheme = row.insertCell();
        tdTheme.className = "rl-td-theme";
        tdTheme.textContent = (it.theme || "").replace(/^Theme \d+: /, "");

        // Subtheme (strip leading "Na. " number prefix)
        const tdSub = row.insertCell();
        tdSub.className = "rl-td-subtheme";
        tdSub.textContent = (it.subtheme || "").replace(/^\d+[a-z]\.\s*/i, "");

        // Tags
        const tdTags = row.insertCell();
        (it.tags || []).slice(0, 3).forEach(t => {
          const s = document.createElement("span");
          s.className = "rl-tag rl-tag--sm";
          s.textContent = t;
          tdTags.appendChild(s);
        });
      });
    }

    wrap.appendChild(table);
  }

  // ── Event Binding ──────────────────────────────────────────────────────────
  function bindEvents() {
    document.querySelectorAll(".rl-view-btn").forEach(btn => {
      btn.addEventListener("click", () => setState("view", btn.dataset.view));
    });

    const bind = (id, key) => {
      const el = document.getElementById(id);
      if (el) el.addEventListener("change", () => setState(key, el.value));
    };
    bind("rl-filter-theme",  "theme");
    bind("rl-filter-status", "status");
    bind("rl-filter-stars",  "stars");
    bind("rl-filter-year",   "year");
    bind("rl-sort",          "sort");

    const searchEl = document.getElementById("rl-search");
    if (searchEl) {
      searchEl.addEventListener("input", () => {
        state.query = searchEl.value.trim();
        render();
      });
    }

    const resetEl = document.getElementById("rl-reset");
    if (resetEl) resetEl.addEventListener("click", resetState);
  }

  // ── Boot ───────────────────────────────────────────────────────────────────
  function boot() {
    const m = state.sort.match(/^(.+)-(asc|desc)$/);
    if (m) { tableSort.key = m[1]; tableSort.dir = m[2]; }

    fetch(DATA_URL)
      .then(r => {
        if (!r.ok) throw new Error(`HTTP ${r.status}: ${DATA_URL}`);
        return r.json();
      })
      .then(data => {
        allItems  = data.items  || [];
        allThemes = data.themes || [];
        meta      = data.meta   || {};
        bindEvents();
        render();
      })
      .catch(err => {
        const el = document.getElementById("rl-container");
        if (el) el.innerHTML = `<p style="color:red">Data load failed: ${err.message}</p>`;
      });
  }

  if (document.readyState === "loading") document.addEventListener("DOMContentLoaded", boot);
  else boot();
})();
